/*
 * tan() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly tan  (test_tan_opt.elf)
 *   2. Linked with toolchain's default tan       (test_tan_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += tan(vx);
#else
    double r = tan(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

#ifndef EN_PERF
static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit_u(uint64_t bits)
{
    volatile double vx = u2d(bits);  /* prevent constant-folding of literal arguments */
    g_acc += tan(vx);
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test suite                                 */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit(DBL_MAX);                  /* 0x7fefffffffffffff */
    emit(-DBL_MAX);

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffff00000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000100000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Pi-grid angles and tan-specific values (14) --- */
    emit(0.52359877559829887308);   /* pi/6: tan = 1/sqrt(3) */
    emit(0.78539816339744830962);   /* pi/4: tan = 1.0 */
    emit(1.04719755119659774615);   /* pi/3: tan = sqrt(3) */
    emit(1.57079632679489661923);   /* pi/2: asymptote */
    emit(3.14159265358979323846);   /* pi: tan = 0 */
    emit(6.28318530717958647692);   /* 2*pi: tan = 0 */
    emit(-0.52359877559829887308);  /* -pi/6 */
    emit(-0.78539816339744830962);  /* -pi/4: tan = -1.0 */
    emit(-1.04719755119659774615);  /* -pi/3 */
    emit(-1.57079632679489661923);  /* -pi/2: asymptote */
    emit(2.35619449019234492884);   /* 3*pi/4: tan = -1.0 */
    emit(2.61799387799149436538);   /* 5*pi/6 */
    emit(-2.35619449019234492884);  /* -3*pi/4 */
    emit(-3.14159265358979323846);  /* -pi */

    /* --- Section 7: Argument reduction stress (8) --- */
    emit(1.0e15);
    emit(1.0e16);
    emit(1.0e17);
    emit(-1.0e15);
    emit(-1.0e17);
    emit(1.23456789012345e15);      /* irrational large */
    emit_u(0x432921fb54442d18ULL);  /* 2^51*(pi/2): Payne-Hanek hard case */
    emit(1.0e20);

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* triplet around pi/2 */
    emit_u(0x3ff921fb54442d17ULL);  /* one ULP below pi/2 */
    emit_u(0x3ff921fb54442d18ULL);  /* pi/2 as double */
    emit_u(0x3ff921fb54442d19ULL);  /* one ULP above pi/2 */
    /* triplet around pi */
    emit_u(0x400921fb54442d17ULL);  /* one ULP below pi */
    emit_u(0x400921fb54442d18ULL);  /* pi as double */
    emit_u(0x400921fb54442d19ULL);  /* one ULP above pi */
    /* triplet around 3*pi/2 */
    emit_u(0x4012d97c7f3321d1ULL);  /* one ULP below 3*pi/2 */
    emit_u(0x4012d97c7f3321d2ULL);  /* 3*pi/2 as double */
    emit_u(0x4012d97c7f3321d3ULL);  /* one ULP above 3*pi/2 */
    /* triplet around 2*pi */
    emit_u(0x401921fb54442d17ULL);  /* one ULP below 2*pi */
    emit_u(0x401921fb54442d18ULL);  /* 2*pi as double */
    emit_u(0x401921fb54442d19ULL);  /* one ULP above 2*pi */
    /* triplet around -pi/2 */
    emit_u(0xbff921fb54442d17ULL);  /* one ULP toward zero from -pi/2 */
    emit_u(0xbff921fb54442d18ULL);  /* -pi/2 as double */
    emit_u(0xbff921fb54442d19ULL);  /* one ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    emit_u(0x3f80000000000000ULL);  /* 2^-127 (very small) */
    emit_u(0x3fb0000000000000ULL);  /* 2^-4 = 0.0625 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26 */
    emit_u(0xbf80000000000000ULL);  /* -2^-127 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-4 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */

    /* --- Section 10: Polynomial branch and hard reduction cases (24) --- */
    /* ULP neighbors of pi/8 */
    emit_u(0x3fd921fb54442d17ULL);  /* one ULP below pi/8 */
    emit_u(0x3fd921fb54442d18ULL);  /* pi/8 as double */
    emit_u(0x3fd921fb54442d19ULL);  /* one ULP above pi/8 */
    /* ULP neighbors of pi/4 */
    emit_u(0x3fe921fb54442d17ULL);  /* one ULP below pi/4 */
    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 as double */
    emit_u(0x3fe921fb54442d19ULL);  /* one ULP above pi/4 */
    /* k*pi: tan ~ 0, catastrophic cancellation */
    emit(9.42477796076937971538);   /* 3*pi */
    emit(12.56637061435917295384);  /* 4*pi */
    emit(15.70796326794896619231);  /* 5*pi */
    emit(31.41592653589793238462);  /* 10*pi */
    /* asymptote stress: near odd multiples of pi/2 */
    emit(7.85398163397448309616);   /* 5*pi/2: asymptote */
    emit(10.99557428756427633461);  /* 7*pi/2: asymptote */
    emit(-7.85398163397448309616);  /* -5*pi/2 */
    /* non-pi normal inputs */
    emit(3.0);
    emit(-3.0);
    emit(1.0e10);
    emit(-1.0e10);
    /* scaled pi/2 patterns at 2^23 and 2^51 magnitude */
    emit_u(0x4169921fb54442d2ULL);  /* 2^23 * (pi/2): Payne-Hanek boundary */
    emit_u(0x432921fb54442d17ULL);  /* one ULP below 2^51*(pi/2) */
    emit_u(0x432921fb54442d19ULL);  /* one ULP above 2^51*(pi/2) */
    /* 3*pi/8 and -3*pi/8: exercises cos-path reconstruction */
    emit_u(0x4002d97c7f3321d2ULL);  /* 3*pi/8 */
    emit_u(0xc002d97c7f3321d2ULL);  /* -3*pi/8 */
    /* double value just inside the last reduction bucket */
    emit_u(0x432921fb40000000ULL);  /* large value near Payne-Hanek boundary */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    double hi = 4.0 * 3.14159265358979323846;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* Sample [0, pi/4] every 4503599627370496 ULP (~200 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe921fb54442d18ULL; /* pi/4 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

